import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as a,o as s,c,a as e,b as p,e as o,f as r}from"./app-bf003ea8.js";const i={},_=r('<p>之前文章提到，职场有三张横亘在头上的大网，你想越过去。穷尽各种努力，但到头来终究会发现，自己越不过去。因为那是<em><strong>客观规律</strong></em>。</p><p>前两张网分别是：年收入100w后极其高昂的税收 和 带不走的位置。</p><p>今天是最后一张大网，<strong>ROE的下滑</strong>。</p><p>本文，我们以一个普通打工人的视角，来看看这最后一条铁律。</p><h4 id="一、什么是roe的下滑" tabindex="-1"><a class="header-anchor" href="#一、什么是roe的下滑" aria-hidden="true">#</a> 一、什么是ROE的下滑</h4><p>你从三四线城市出生，今年毕业了，年入20w左右。一开始全部的个人财富，就是农村的爸妈为你垫付的三个月房租，每个月800元，总共2400。最多再算一下你的其他零七零八的东西，共算你总资产5000元。</p><p>那么请问，第一年你赚了20w后，今年你作为一个企业的ROE是多少。</p><p>很简单，第零年底5000（学习-家教偶尔挣钱），第一年底16w（初入职场-非常节俭）。</p><p>PS：这16w本来你可以留下更多，但是因为补贴家用，你支持了家里2w。</p><p>那么第一年ROE是：<strong>3100%，是的</strong>，你没有看错，你今年的ROE是多少，百分之三千一。</p><p>我们继续推演，然后又过一年，你又赚了17w。</p><p>第二年底（职场第二年-相对节俭），那么你总资产33w，第二年ROE是：106%。</p><p>继续第三年（涨薪3k-节俭），赚了20w，总资产53w，第三年ROE是：60.6%。</p>',13),w={href:"https://xueqiu.com/S/SH600519?from=status_stock_match",target:"_blank",rel:"noopener noreferrer"},h=e("figure",null,[e("img",{src:"https://xqimg.imedao.com/18f758186a161cbe3fe24b48.png!800.jpg",alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),E={href:"https://xueqiu.com/S/SH600519?from=status_stock_match",target:"_blank",rel:"noopener noreferrer"},l=e("strong",null,"吊打茅台",-1),d=r("<p>第四年（跳槽涨5k-开销增加，支持父亲换车花9w），赚15w，总资产68w，第四年ROE是：28%</p><p>第五年（普调2k-正常开销），赚26w，总资产94w，即将突破100w大关。第五年ROE：38%。没有了去年的大开销，今年ROE还是很猛。</p><p>第六年（公司排挤不顺-再次跳槽-涨6k-正常开销），赚30w，总资产124w。第六年ROE：31.9%，你感慨有点悬乎，要是没有这次跳槽，组长位置又迟迟升不上去，自己就差点要维持不住30%以上的涨幅了。</p><p>第七年（祈稳-正常开销），赚30w，总资产154w。第七年，看着资产到了150w，你欣慰的笑了。本科毕业至今，你也不过才工作七年，21岁毕业，今年才28岁，还算得上年轻。平时出去玩，你对自己和女友，也是完全不吝啬，对家人你也多加照顾。工作至此，你的父母也是渐渐感觉你可以依赖，虽然他们还是像之前一样打着月薪3k的工作，但终归是早就没了压力。也不再非指望他们工作不可。今年你的ROE是：24%。至此你的工资近46w。</p><p>第八年（祈稳-开销增加），赚30w，总资产184w。第八年，你知道下一步不当组长，已经很难有更进一步的职场发展了。今年你的ROE是：19%。值得一提的是，今年你炒股亏了3w。好在有高工资兜底，才显得不那么伤。19%的ROE，你的ROE水平似乎已经和某些空调企业一样了。</p><p>第九年（结婚了-普调3k），今年多攒了15w。还贷款买了一套房，因为房子也算是你的资产，总资产就视为不加不减。总资产199w，今年ROE：8%</p><p>第十年（孩子出生-祈稳-开销增加），父母看到你一切稳定，渐渐越来越放心，他们已经完全算是老人了。今年攒26w。总资产225w，今年ROE：13%。</p><p>…</p><p>第十一年（谋求新的机会当组长），赚25w，总资产250w。ROE：11%</p><p>第十二年（跳出去当上组长了，但是被裁的），虽然职务更体面了，但是只有你自己心里知道，其实这份工作比之前还要累了。月薪虽然涨了，但到手的年终奖其实少了，其实还不如之前那份工作。赚26w。总资产276w，ROE：10.4%。</p><p>第十二年（33岁生日）。赚27w。总资产303w。ROE：9.7%。现在你的ROE已经和一些水电煤公司一样了。<strong>今年，一个很久不见的朋友和你吃了个饭，你才知道，原来他在职场第六年的时候，工作的公司上市了</strong>。</p><p>他学历不如你，之前他薪资也只有20w。但是一上市，他股票可按照20PE兑现。近似等于他一次性赚了20年钱，总共400w。而且公司上市后，公司疯狂扩张，作为老员工，他现在已经是副总监了，年入100w。听完你唏嘘感慨，仿佛第一次知道资本市场的巨大魅力。</p><p><strong>你心里暗暗算账，20PE，等于把20年的利润，上市的时候，打包一次性发给你。而且这时候，你即便走了，也可以带走这20年利润。天哪，自己之前怎么没有想过这个事情，这仿佛偷走了时间？自己更加辛苦的打工12年，怎么还比不上一次上市？</strong></p>",13),O={href:"https://xueqiu.com/S/SZ399417?from=status_stock_match",target:"_blank",rel:"noopener noreferrer"},R=r('<p>第十四年，赚28w，总资产359w。8.4%。</p><p>第十五年，赚28w，总资产387w。7.2%。</p><p>…</p><p>至此，你的ROE跌到了7%。这在A股，可能都属于你看不上的公司了。你的薪水收入其实一直再涨，是一头现金奶牛。但你的<strong>资产收益率一直在跌</strong>。</p><h4 id="二、逃不出去" tabindex="-1"><a class="header-anchor" href="#二、逃不出去" aria-hidden="true">#</a> 二、逃不出去</h4><p>你在职场，逃得出ROE下滑的牢笼么？</p><figure><img src="https://xqimg.imedao.com/18f758186a161cbe3fe24b48.png!800.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>',7),g={href:"https://xueqiu.com/S/SH600519?from=status_stock_match",target:"_blank",rel:"noopener noreferrer"},f=r('<p>一直维持30%的ROE有多难？一只大象却能按照30%以上的提升狂奔，有多难！？</p><p>职场十五年，年年在赚钱，最后攒了387w，这难道不是一个壮举？这15年，你肯定都不轻松，每一个阶段，你都在决策。</p><p>多少个夜晚，你都在内心的思考推演下一步的方向，黑灯瞎火，坐在电脑前算钱。</p><p>职场的模型，是加法模型。市场为这个岗位定的工资是多少，最后工资就是多少。每年你的总资产都加这个数字。</p><p>加法模型其实是没有参考你的资产情况的，你不论资产千万还是资产为零，来打这份工，你的工资都是那么多。</p><p>这等于什么，除非职场今年涨薪20%，明年又涨薪20%，否则涨薪总有变慢的一天，那就是ROE下滑的开始。</p><p>工资上涨是有天花板的。天花板就是市场其他人的工资。你的工资足够雇佣两个、三个同样位置的人，公司为何要选择你呢？</p><p>职场大家都是零件，并没有真正的不可替代性。</p><p>职场之道，ROE下滑就是铁律！</p><p>现在你总资产400w，赚40w，ROE就是10%。将来某一天，你总资产800w了，再赚40w，ROE变成了5%。</p><p>这里面是什么，ROE只有5%，我找点不错的定期存着ROE就能有4%欸。</p><p>但给你打工，兢兢业业，还要讨好领导，还经常加班，最后也是赚这5%。</p><p>提升了什么，提升了1%，这种提升，<strong>我不如不要</strong>，干脆把职场全部时间留出来，我不如搞投资，不如研究哪家银行定期给的钱多。</p><p>这样我换回了全部时间，带来了无限可能性。</p><h4 id="三、结语" tabindex="-1"><a class="header-anchor" href="#三、结语" aria-hidden="true">#</a> 三、结语</h4><p>本文写了一个打工人的一生，他努力，奋进，在生活中，这样努力15年不懈怠，最终攒下近400w的，算是一个小奇迹。</p><p>但我们也看到了，ROE在急速下滑。这就是为何我说，ROE下滑是横亘在职场上的大网。</p><p>再下滑，就不值得为此付出全部精力，不如把时间留下来，做其他提升ROE的事情。</p><p>所以很多时候，不是你的技能不够，或者公司裁员让你离开职场，而是ROE下滑到只有10%了，未来预计还会下滑，这时候聪明人一定在干什么，跳船啊！再为公司打工，已不值得。</p><p>这就是为什么，有钱人往往不去职场。如果开局千万资产，那么去往职场的第一步就被堵住了，难道先去职场拿20w每年，累死累活换来2%的ROE增长？</p>',20);function m(u,k){const t=a("ExternalLinkIcon");return s(),c("div",null,[_,e("p",null,[p("一直到这里，还是多么可怕的ROE啊。想我大A多少只股票，多少个大牛，例如以其中牛中牛的"),e("a",w,[p("茅台"),o(t)]),p("，他最猛的时候，ROE多高呢？")]),h,e("p",null,[e("a",E,[p("茅台"),o(t)]),p("最高40%的ROE。头三年，你的资产收益率，"),l,p("。")]),d,e("p",null,[p("第十三年（34岁-跳槽到"),e("a",O,[p("新能源车"),o(t)]),p("企），你预感到这可能是你最后一次跳槽，有点急不可耐，就像你之前无数次跳槽一样。你依稀想起来，自己每一次跳槽之前都说，下一次跳槽的时候，要精挑细选，但是每一次跳槽的时候，你都慌忙的跳了。虽然结果来看，都还不错。这次你是想赶在35岁前完成跳槽。涨薪2k（对方薪资给不了更多了，但权限可以给更多），部门小负责人。今年赚28w。总资产331w。ROE：9%。")]),R,e("p",null,[p("现在再看这张图，你知道"),e("a",g,[p("茅台"),o(t)]),p("的厉害之处了么？")]),f])}const S=n(i,[["render",m],["__file","普通打工人的一生.html.vue"]]);export{S as default};
